#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        uint64_t sum = 0, orv = 0;
        for(int i=0;i<N;i++){
            uint32_t x; scanf("%u", &x);
            sum += x;
            orv |= x;
        }
        printf("%llu\n", (unsigned long long)(sum | orv));
    }
    return 0;
}

